#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-07-23
#
# =============================================================================
# check-workflow-gates.sh — fail if a workflow gates on a label that does not
# exist in the repository.
# =============================================================================
# The failure class this exists for: Claude PR Review gated its pull_request
# path on `needs-claude-review`, a label that was never created. The condition
# was therefore permanently false, the workflow showed "skipped" on every PR
# (which reads as benign), and no PR was ever reviewed — for the repo's whole
# history. A gate keyed on a non-existent label is a dead gate, and a dead gate
# is worse than no gate because it looks like coverage.
#
# This walks .github/workflows/*.yml, extracts every label referenced in a
# gating expression, and fails if any of them is absent from the live label set.
#
# Scope, honestly: it checks LABEL EXISTENCE only. It does not detect
# tautologically-false `if:` conditions (undecidable in general) or verify that
# a validator is in branch protection (needs an admin-scoped token this CI job
# does not hold). Those remain manual review concerns.
#
# Usage:
#   GH_REPO=owner/repo bash scripts/check-workflow-gates.sh
#   (GH_REPO defaults to the gh-resolved repo when run locally.)
# =============================================================================

set -euo pipefail

WF_DIR="${WF_DIR:-.github/workflows}"
REPO="${GH_REPO:-$(gh repo view --json nameWithOwner --jq .nameWithOwner || echo "")}"

if [[ -z "$REPO" ]]; then
  echo "::error::Cannot resolve repository. Set GH_REPO=owner/repo."
  exit 1
fi

# grep that tolerates no-match (exit 1, expected) but still surfaces real
# errors (exit >=2, e.g. an unreadable file). No blanket `|| true`.
greptol() {
  local rc=0
  grep "$@" || rc=$?
  [[ "$rc" -le 1 ]] || return "$rc"
}

# Live label set, one per line. If the API call fails, LABELS is empty and we
# refuse to pass rather than vacuously approve — the exact bug this gate exists
# to prevent.
mapfile -t LABELS < <(gh api "repos/${REPO}/labels" --paginate --jq '.[].name' | sort -u)
if [[ ${#LABELS[@]} -eq 0 ]]; then
  echo "::error::Could not list labels for ${REPO} (token scope?). Refusing to pass vacuously."
  exit 1
fi
label_exists() {
  local target="$1" l
  for l in "${LABELS[@]}"; do [[ "$l" == "$target" ]] && return 0; done
  return 1
}

# Referenced labels: two gating idioms are used across this repo's workflows.
#   contains(github.event.pull_request.labels.*.name, 'LABEL')
#   github.event.label.name == 'LABEL'
# Extract the single-quoted operand from each. author_association lists inside
# fromJSON(...) are not labels; requiring the labels/label context on the same
# line excludes them.
extract_refs() {
  greptol -rhoE "contains\(github\.event\.pull_request\.labels\.\*\.name, *'[^']+'\)" "$WF_DIR"/*.yml \
    | greptol -oE "'[^']+'" | tr -d "'"
  greptol -rhoE "github\.event\.label\.name *== *'[^']+'" "$WF_DIR"/*.yml \
    | greptol -oE "'[^']+'$" | tr -d "'"
}

missing=0
while read -r ref; do
  [[ -z "$ref" ]] && continue
  if label_exists "$ref"; then
    echo "  ok   gate label '${ref}' exists"
  else
    echo "::error::Workflow gate references label '${ref}', which does not exist in ${REPO}. Create it (a gate on a missing label never fires), or remove the reference."
    missing=$((missing + 1))
  fi
done < <(extract_refs | sort -u)

if [[ "$missing" -gt 0 ]]; then
  echo "::error::${missing} workflow gate label(s) do not exist — see above."
  exit 1
fi
echo "All workflow gate labels exist."
